// Get binary data from the Read CSV File node
const items = $input.all();
const binaryPropertyName = 'data';
const binaryData = items[0].binary[binaryPropertyName];

// Convert binary data to string
let csvContent;
if (binaryData.data instanceof Buffer) {
  csvContent = binaryData.data.toString('utf8');
} else if (typeof binaryData.data === 'string') {
  csvContent = Buffer.from(binaryData.data, 'base64').toString('utf8');
} else {
  csvContent = binaryData.data;
}

// Parse CSV helper function that handles quoted fields
function parseCSVLine(line) {
  const result = [];
  let current = '';
  let inQuotes = false;

  for (let i = 0; i < line.length; i++) {
    const char = line[i];

    if (char === '"') {
      inQuotes = !inQuotes;
    } else if (char === ',' && !inQuotes) {
      result.push(current.trim());
      current = '';
    } else {
      current += char;
    }
  }
  result.push(current.trim());
  return result;
}

// Parse CSV content
const lines = csvContent.trim().split('\n');
const headers = parseCSVLine(lines[0]);

const outputItems = [];
for (let i = 1; i < lines.length; i++) {
  if (lines[i].trim()) {
    const values = parseCSVLine(lines[i]);
    const ticket = {};
    headers.forEach((header, index) => {
      ticket[header] = values[index] || '';
    });
    outputItems.push({ json: ticket });
  }
}

return outputItems;
